//! Choice-point stack and backtracking.
//!
//! Per `sw-cor24-prolog/docs/vm-spec.md` §4.1. TRY pushes a frame with
//! the current A0-A7 / CP / HP / TR and the alternative PC. RETRY
//! restores those fields and updates the alt. TRUST pops. FAIL jumps
//! to the top frame's alt (restoration happens when RETRY/TRUST
//! executes).

use super::heap::unwind_trail;

#[derive(Clone, Copy, Debug)]
pub struct ChoicePt {
    pub saved_regs: [u32; 8],
    pub alt_pc: usize,
    pub saved_cp: usize,
    pub saved_hp: usize,
    pub saved_tr: usize,
    pub saved_ep: usize,
}

pub fn push_choice(
    stack: &mut Vec<ChoicePt>,
    regs: &[u32; 16],
    alt_pc: usize,
    cp: usize,
    hp: usize,
    tr: usize,
    ep: usize,
) {
    let mut saved_regs = [0u32; 8];
    saved_regs.copy_from_slice(&regs[..8]);
    stack.push(ChoicePt {
        saved_regs,
        alt_pc,
        saved_cp: cp,
        saved_hp: hp,
        saved_tr: tr,
        saved_ep: ep,
    });
}

pub fn restore_top<F>(
    stack: &[ChoicePt],
    regs: &mut [u32; 16],
    heap: &mut Vec<u32>,
    trail: &mut Vec<u32>,
    mut truncate_env: F,
) -> Option<usize>
where
    F: FnMut(usize),
{
    let top = stack.last()?;
    regs[..8].copy_from_slice(&top.saved_regs);
    unwind_trail(top.saved_tr, heap, trail);
    heap.truncate(top.saved_hp);
    truncate_env(top.saved_ep);
    Some(top.saved_cp)
}

pub fn update_alt(stack: &mut [ChoicePt], new_alt: usize) {
    if let Some(top) = stack.last_mut() {
        top.alt_pc = new_alt;
    }
}

pub fn pop(stack: &mut Vec<ChoicePt>) {
    stack.pop();
}

pub fn top_alt(stack: &[ChoicePt]) -> Option<usize> {
    stack.last().map(|c| c.alt_pc)
}

#[cfg(test)]
mod tests {
    use super::*;
    use super::super::heap::{alloc_unbound, bind, deref, is_unbound, make, tag, TAG_ATOM};

    #[test]
    fn push_and_pop_restores_no_state_if_empty() {
