/* vm_main.plsw -- LAM Virtual Machine entry point
 *
 * Contains VM_INIT, VM_RUN dispatch loop, and MAIN.
 * Runtime primitives are in separate library modules:
 *   vm_regs.plsw   -- REG_GET, REG_SET
 *   vm_heap.plsw   -- cell helpers, heap, deref, bind, trail
 *   vm_choice.plsw -- choice-point push/restore/pop
 *   vm_io.plsw     -- PRINT_INT, VM_TRACE, atom table
 *   vm_tests.plsw  -- test program loaders
 *
 * Build:
 *   pipeline.sh include/cell.msw include/memory.msw \
 *     include/opcodes.msw include/frames.msw \
 *     include/vmglob.msw \
 *     src/vm/vm_regs.plsw src/vm/vm_heap.plsw \
 *     src/vm/vm_choice.plsw src/vm/vm_io.plsw \
 *     src/vm/vm_tests.plsw src/vm/vm_main.plsw
 */

%INCLUDE cell;
%INCLUDE memory;
%INCLUDE opcodes;
%INCLUDE frames;
%INCLUDE vmglob;

/* --------------------------------------------------------
 * VM initialization
 * -------------------------------------------------------- */

VM_INIT: PROC;
    DCL I INT;

    /* Zero all memory */
    DO I = 0 TO 7703;
        MEM(I) = 0;
    END;

    /* Populate atom table */
    CALL ATOM_INIT;

    /* Set initial register values */
    CALL REG_SET(REG_PC, CODE_BASE);
    CALL REG_SET(REG_HP, HEAP_BASE);
    CALL REG_SET(REG_TR, TRAIL_BASE);
    CALL REG_SET(REG_EP, ENV_BASE);
    G_ET = ENV_BASE;
    CALL REG_SET(REG_BP, CP_BASE);
    CALL REG_SET(REG_MODE, 0);
END;

/* --------------------------------------------------------
 * Fetch / decode / dispatch loop
 * -------------------------------------------------------- */

VM_RUN: PROC;
    DCL PC INT;
    DCL IMM INT;
    DCL REGVAL INT;

    G_RUNNING = 1;

    DO WHILE (G_RUNNING = 1);
        PC = REG_GET(REG_PC);
        G_INST = MEM(PC);
        ?INST_DECODE(SRC(ADDR(G_INST)));
        /* CALL VM_TRACE(PC, G_OP);  -- per-step trace, gated off for
         * speed. Uncomment when debugging a specific failing test;
         * it dominates UART traffic and test runtime otherwise. */

        SELECT;
            WHEN (G_OP = OP_NOP) DO;
                CALL REG_SET(REG_PC, PC + 1);
            END;

            WHEN (G_OP = OP_HALT) DO;
                CALL UART_PUTS(ADDR(M_HALT));
                G_RUNNING = 0;
            END;

            /* PUT_CONST Ai, [imm] -- 2-cell */

