fn emit_query_clause(
    clause: &Clause,
    atoms: &AtomTable,
    out: &mut BoundedArr<Instr, MAX_INSTR>,
) -> Result<(), CompileError> {
    push_i(out, Instr::Label(lbl_query()?))?;
