    let s = core::str::from_utf8(bytes).expect("ascii ident is valid utf8");
    let name = BoundedStr::<ATOM_CAP>::from_str(s)
        .map_err(|_| TokenizeError::IdentTooLong { pos: start })?;
    Ok(Token::Atom(name))
}

