            vm.regs[xi_ix] = vm.heap[vm.up];
            vm.up += 1;
        }
        UnifyMode::Write => {
            let slot = vm.heap.len();
            vm.heap.push(make_ref(slot));
            vm.regs[xi_ix] = make_ref(slot);
            vm.up = slot + 1;
        }
    }
    vm.pc += 1;
