fn emit_list_spine(
    ai: u8,
    first_args: &BoundedArr<TermIdx, MAX_ARGS>,
    clause: &Clause,
    atoms: &AtomTable,
    rm: &mut RegMap,
    cursor_x: u8,
    dot_id: AtomId,
    nil_id: AtomId,
    out: &mut BoundedArr<Instr, MAX_INSTR>,
) -> Result<(), CompileError> {
    let mut args = first_args;
    loop {
        push_i(out, Instr::GetStruct { ai, atom: dot_id, arity: 2 })?;
        let head_ti = *args.get(0).expect("cons head");
        let tail_ti = *args.get(1).expect("cons tail");
        let head = *clause.subterm(head_ti).ok_or(CompileError::BadSubterm)?;
        let tail = *clause.subterm(tail_ti).ok_or(CompileError::BadSubterm)?;
        emit_list_element(&head, atoms, rm, out)?;
        match tail {
            Term::Nil => {
                push_i(out, Instr::UnifyConst { atom: nil_id })?;
                return Ok(());
            }
            Term::Struct { functor, args: next } if functor == dot_id && next.len() == 2 => {
                push_i(out, Instr::UnifyVar { xi: cursor_x })?;
                push_i(out, Instr::PutVal { ai, xi: cursor_x })?;
                args = unsafe_extend_lifetime(&next, clause)?;
            }
            _ => return Err(CompileError::StructArg),
        }
    }
}

